export const allIconNames = ICONS_WITH_TAGS.map(i => i.n)

export function searchIcons(term) {
  const lower = term.toLowerCase()
  return ICONS_WITH_TAGS.filter(i => 
    i.n.includes(lower) || i.t.includes(lower)
  ).map(i => i.n)
}

export default allIconNames
